import { ApiProperty, ApiPropertyOptional } from '@nestjs/swagger';
import { z } from 'zod';

import { ValidationUtil } from '@/app/common/utils/validation.util';

export class GetTokenDto {
  @ApiProperty({ default: 'test_user1_super_admin@example.com' }) email: string;
  @ApiProperty({ default: 'test123' }) password: string;
}

export const getTokenDtoValidator = () =>
  z.object({
    email: ValidationUtil.defaultEmail,
    password: ValidationUtil.defaultPassword,
  });

export type GetTokenDtoValidated = z.infer<
  ReturnType<typeof getTokenDtoValidator>
>;

export class EmailVerificationStatusDto {
  @ApiProperty({ default: 'new-user@knowhere.co.jp' }) email: string;
}

export const emailVerificationStatusDtoValidator = () =>
  z.object({
    email: ValidationUtil.defaultEmail,
  });

export type EmailVerificationStatusDtoValidated = z.infer<
  ReturnType<typeof emailVerificationStatusDtoValidator>
>;

export class SignupDto {
  @ApiPropertyOptional({ default: 'foobar' }) name?: string;
  @ApiProperty({ default: 'new-user@knowhere.co.jp' }) email: string;
  @ApiProperty({ default: 'code' }) inviteMode: 'code' | 'link';
  @ApiProperty({ type: 'string', example: '2000-01-01' })
  birthday?: Date | null;
}

export const signUpDtoValidator = () =>
  z.object({
    name: ValidationUtil.defaultUserName.optional(),
    email: ValidationUtil.defaultEmail,
    inviteMode: z.enum(['code', 'link']).optional(),
    birthday: z.string().date().nullable().optional(),
  });

export type SignUpDtoValidated = z.infer<ReturnType<typeof signUpDtoValidator>>;

export class EmailDto {
  @ApiProperty() email: string;
}
export const emailDtoValidator = () =>
  z.object({
    email: ValidationUtil.defaultEmail,
  });

export type EmailDtoValidated = z.infer<ReturnType<typeof emailDtoValidator>>;

export class CodeVerificationDto {
  @ApiProperty() email: string;
  @ApiProperty() code: string;
}

export const codeVerificationDtoValidator = () =>
  z.object({
    email: ValidationUtil.defaultEmail,
    code: z.string().max(16),
  });

export type CodeVerificationDtoValidated = z.infer<
  ReturnType<typeof codeVerificationDtoValidator>
>;

export class EmailChangeVerificationDto {
  @ApiProperty() uid: string;
  @ApiProperty() email: string;
  @ApiProperty() t: string; // token
  @ApiPropertyOptional() redirect?: string;
}

export const emailChangeVerificationDtoValidator = () =>
  z.object({
    uid: z.string().uuid(),
    email: ValidationUtil.defaultEmail,
    t: z.string().max(1024),
    // t is made in UsersService. 1024 is enough.
    redirect: z.string().max(1024).optional(),
    // Ex) https://[domain]/auth/recover-callback. 1024 is enough.
  });

export type EmailChangeVerificationDtoValidated = z.infer<
  ReturnType<typeof emailChangeVerificationDtoValidator>
>;

export class PasswordChangeTokenDto {
  @ApiProperty() userId: string;
  @ApiProperty() password: string;
  @ApiProperty() token: string; // token
}

export const passwordChangeTokenDtoValidator = () =>
  z.object({
    userId: z.string().uuid(),
    password: ValidationUtil.defaultPassword,
    token: z.string().max(1024),
    // token is made in UsersService. 1024 is enough.
  });

export type PasswordChangeTokenDtoValidated = z.infer<
  ReturnType<typeof passwordChangeTokenDtoValidator>
>;

