import { Injectable, Logger } from '@nestjs/common';
import bcrypt from 'bcrypt';
import _ from 'lodash';
import moment from 'moment';
import {
  DataSource,
  EntityManager,
  In,
  IsNull,
  LessThanOrEqual,
  Not,
} from 'typeorm';
import { v4 as uuidv4 } from 'uuid';

import { AppConstants } from '@/app/common/constants/app.constants';
import { Coded, CodedMethod, Service } from '@/app/common/decorators';
import { RoleChecker } from '@/app/common/types';
import { ImageCompressionUtil } from '@/app/common/utils/image-compression.util';
import { StringUtil } from '@/app/common/utils/string.util';
import { TimeUtil } from '@/app/common/utils/time.util';
import { CodedForbiddenException } from '@/app/exceptions/errors/coded-forbidden.exception';
import { CodedInvalidArgumentException } from '@/app/exceptions/errors/coded-invalid-argument.exception';
import { ErrorInfo } from '@/app/exceptions/errors/error-info';
import { Ball } from '@/app/models/ball';
import { BallPosition } from '@/app/models/ball-position';
import { BoundingBox } from '@/app/models/bounding-box';
import {
  PasswordCheckDtoValidated,
  UserStatusVerifyDtoValidated,
} from '@/app/models/dto/if.dto';
import {
  NotificationForUserSearchDtoValidated,
  UserNotificationUpdateDtoValidated,
} from '@/app/models/dto/notification.dto';
import { TeamAndUserCreateDtoValidated } from '@/app/models/dto/team.dto';
import { UserSearchDtoValidated } from '@/app/models/dto/user.dto';
import {
  Notification,
  StructuredNotification,
} from '@/app/models/notification';
import { Player } from '@/app/models/player';
import { Profile } from '@/app/models/profile';
import { Resource } from '@/app/models/resource';
import { RoleGroup, RoleGroupName } from '@/app/models/role-group';
import { Session } from '@/app/models/session';
import { Subscription } from '@/app/models/subscription';
import { Team, TeamType } from '@/app/models/team';
import { TeamDeletionRecord } from '@/app/models/team-deletion-record';
import { TeamSubscription } from '@/app/models/team-subscription';
import { User } from '@/app/models/user';
import {
  UserDeletionReason,
  UserDeletionRecord,
} from '@/app/models/user-deletion-record';
import { UserNotification } from '@/app/models/user-notification';
import { UserRole } from '@/app/models/user-role';
import { NotificationsPersistence } from '@/app/persistence/notifications.persistence';
import { TeamItemsPersistence } from '@/app/persistence/team-items.persistence';
import { TeamSubscriptionsPersistence } from '@/app/persistence/team-subscriptions.persistence';
import { TeamsPersistence } from '@/app/persistence/teams.persistence';
import { UsersPersistence } from '@/app/persistence/users.persistence';
import { CognitoProvider } from '@/app/providers/cognito.provider';
import { ConfigProvider } from '@/app/providers/config.provider';
import { EmailProvider } from '@/app/providers/email.provider';
import { I18nProvider } from '@/app/providers/i18n.provider';
import { StorageProvider } from '@/app/providers/storage.provider';
import { BaseService } from '@/app/services/base-service';
import { LimitsService } from '@/app/services/limits.service';

import { CodedException } from '../exceptions/errors/coded-exception';

type MinimumUserInfo = {
  id: string;
  email?: string | null;
};

@Coded('SUS')
@Service()
@Injectable()
export class UsersService extends BaseService {
  private readonly logger = new Logger(UsersService.name);

  constructor(
    private readonly usersPersistence: UsersPersistence,
    private readonly teamsPersistence: TeamsPersistence,
    private readonly teamItemsPersistence: TeamItemsPersistence,
    private readonly teamSubscriptionsPersistence: TeamSubscriptionsPersistence,
    private readonly notificationsPersistence: NotificationsPersistence,
    private readonly configProvider: ConfigProvider,
    private readonly storageProvider: StorageProvider,
    private readonly emailProvider: EmailProvider,
    private readonly i18n: I18nProvider,
    private readonly datasource: DataSource,
    private readonly cognitoProvider: CognitoProvider,
    private readonly limitsService: LimitsService,
  ) {
    super();
  }

  static readonly ERROR_CODES = {
    USER_ALREADY_EXISTS: ErrorInfo.getBuilder('UAE', 'user_already_exists'),
    INVALID_EMAIL: ErrorInfo.getBuilder('IVEM', 'invalid_email'),
    INVALID_USER_ID: ErrorInfo.getBuilder('IVUID', 'invalid_user_id'),
    INVALID_TEAM_ID: ErrorInfo.getBuilder('IVTID', 'invalid_team_id'),
    INVALID_ROLE_GROUP_ID: ErrorInfo.getBuilder(
      'IVRGID',
      'invalid_role_group_id',
    ),
    INVALID_NOTIFICATION_ID: ErrorInfo.getBuilder(
      'IVNTFID',
      'invalid_notification_id',
    ),
    INVALID_PLAN_ID: ErrorInfo.getBuilder('IVPLID', 'invalid_plan_id'),
    USER_NOT_FOUND: ErrorInfo.getBuilder('UNF', 'invalid_user'),
    USER_ALREADY_IN_USE: ErrorInfo.getBuilder('AIU', 'already_in_use'),
    USER_UNAVAILABLE: ErrorInfo.getBuilder('UUA', 'user_unavailable'),
    INVALID_URL: ErrorInfo.getBuilder('IVUR', 'invalid_url'),
    INVALID_TOKEN: ErrorInfo.getBuilder('IVTK', 'invalid_token'),
    INVALID_CODE: ErrorInfo.getBuilder('IVCD', 'invalid_code'),
    LINK_EXPIRED: ErrorInfo.getBuilder('LEX', 'link_expired'),
    CODE_EXPIRED: ErrorInfo.getBuilder('CDEX', 'code_expired'),
    TEAM_ADMIN_ABSENCE: ErrorInfo.getBuilder('TEADAB', 'team_admin_absence'),
    PERSONAL_USER_ABSENCE: ErrorInfo.getBuilder(
      'PEUSAB',
      'personal_user_absence',
    ),
    SINGLE_USER_TEAM_INVITATION_NOT_ALLOWED: ErrorInfo.getBuilder(
      'SUTINA',
      'single_user_team_invitation_not_allowed',
    ),
    BIRTHDAY_ALREADY_SET: ErrorInfo.getBuilder('BAS', 'birthday_already_set'),
    USER_MUST_BE_AT_LEAST_13_YEARS_OLD: ErrorInfo.getBuilder(
      'UMB',
      'user_must_be_at_least_13_years_old',
    ),
  };

  get EC() {
    return UsersService.ERROR_CODES;
  }

  /**
   * Clean up a user account if it has been deactivated.
   *
   * - Deletes the user if the account is deactivated or scheduled for
   *   deletion.
   * - Does not delete active or unconfirmed users.
   * - Throws an exception if the user is active or unconfirmed, depending on
   *   the provided options.
   * - Deactivates related teams if the user was deleted.
   *
   * @param email The email address of the user to check and possibly delete.
   * @param options Optional behavior flags:
   *   - `throwErrorIfUserIsActive` (default: false): Throws if the user is
   *     active.
   *   - `throwErrorIfUserIsUnconfirmed` (default: false): Throws if the user
   *     has not confirmed their account.
   * @throws CodedInvalidArgumentException if the user is active or
   *     unconfirmed and the corresponding flag is enabled.
   * @returns The user found and whether it was deleted.
   */
  @CodedMethod('CUID')
  private async cleanUserIfDeactivated(
    email: string,
    parameters: {
      joinProfileOnUser?: boolean;
      throwErrorIfUserIsActive: boolean;
      throwErrorIfUserIsUnconfirmed: boolean;
    },
  ): Promise<{ user: User | null; isDeleted: boolean }> {
    const cbuilder = this.getCodeBuilder();

    // Search the user with email regardless of its condition,
    // i.e., even if it was deleted or scheduled deletion.
    const { user, teamIds } = await this.datasource.manager.transaction(
      async (t) => {
        const user = await this.usersPersistence.findUserByEmail(t, email, {
          joinUserRole: true,
          joinProfile: parameters.joinProfileOnUser,
          includeDeletedUser: true,
          includeDeletionScheduledUser: true,
        });

        return {
          user,
          teamIds: user?.userRoles.map((x) => x.teamId) ?? [],
        };
      },
