  /**
   * Clean up a user account if it has been deactivated.
   *
   * - Deletes the user if the account is deactivated or scheduled for
   *   deletion.
   * - Does not delete active or unconfirmed users.
   * - Throws an exception if the user is active or unconfirmed, depending on
   *   the provided options.
   * - Deactivates related teams if the user was deleted.
   *
   * @param email The email address of the user to check and possibly delete.
   * @param options Optional behavior flags:
   *   - `throwErrorIfUserIsActive` (default: false): Throws if the user is
   *     active.
   *   - `throwErrorIfUserIsUnconfirmed` (default: false): Throws if the user
   *     has not confirmed their account.
   * @throws CodedInvalidArgumentException if the user is active or
   *     unconfirmed and the corresponding flag is enabled.
   * @returns The user found and whether it was deleted.
   */
  @CodedMethod('CUID')
  private async cleanUserIfDeactivated(
    email: string,
    parameters: {
      joinProfileOnUser?: boolean;
      throwErrorIfUserIsActive: boolean;
      throwErrorIfUserIsUnconfirmed: boolean;
    },
  ): Promise<{ user: User | null; isDeleted: boolean }> {
    const cbuilder = this.getCodeBuilder();

    // Search the user with email regardless of its condition,
    // i.e., even if it was deleted or scheduled deletion.
    const { user, teamIds } = await this.datasource.manager.transaction(
      async (t) => {
        const user = await this.usersPersistence.findUserByEmail(t, email, {
          joinUserRole: true,
          joinProfile: parameters.joinProfileOnUser,
          includeDeletedUser: true,
          includeDeletionScheduledUser: true,
        });

        return {
          user,
          teamIds: user?.userRoles.map((x) => x.teamId) ?? [],
        };
      },
    );

    if (!user) {
      this.logger.debug(
        `[Cleaning] The user with email=${email} not found. Skipped.`,
      );
      // The user having the email is not found, then do nothing.
      return { user: null, isDeleted: false };
    }

    const userId = user.id;

    const isUnconfirmed = !user.hashedPassword;
    const isPendingDeletion = !!user.deletedAt || !!user.deletionScheduledAt;
    const isActive = !isPendingDeletion && !isUnconfirmed;
    const shouldThrowError =
      (parameters.throwErrorIfUserIsActive && isActive) ||
      (parameters.throwErrorIfUserIsUnconfirmed && isUnconfirmed) ||
      isPendingDeletion; // TODO: 削除処理の完成までの一時的な措置：https://knowhere-org.slack.com/archives/C07D9BA4A9W/p1760166939088579

    if (shouldThrowError) {
      throw new CodedInvalidArgumentException(
        this.code,
        this.EC.USER_ALREADY_IN_USE(cbuilder.build()),
      );
    }

    if (!isPendingDeletion) {
      // Do not delete a user who is not for pending deletion
      return { user, isDeleted: false };
    }

    this.logger.debug(`Cleaning user: u=${userId}`);

    await this.deleteUsers([user.id]);
    await this.datasource.transaction(async (t) => {
      await this.teamsPersistence.deactivateTeamsIfNeeded(t, teamIds);
    });

    return { user, isDeleted: true };
  }

  @CodedMethod('CIUD')
  private async createInitialUserData(
    t: EntityManager,
    userId: string,
    data: {
      name: string;
      email: string;
      birthday?: string | null;
      profileImageUrl?: string | null;
      hashedPassword?: string;
      verificationCode?: string;
      verificationCodeExpiration?: Date;
      emailVerificationToken?: string;
      emailVerificationTokenExpiration?: Date;
      emailVerified?: boolean;
    },
    requestContext: { lang: string | null } = { lang: null },
  ) {
    const cbuilder = this.getCodeBuilder();
    const now = new Date();

    await t.save(User, {
      id: userId,
      email: data.email,
      hashedPassword: data.hashedPassword,
      verificationCode: data.verificationCode,
      verificationCodeExpiration: data.verificationCodeExpiration,
      emailVerificationToken: data.emailVerificationToken,
      emailVerificationTokenExpiration: data.emailVerificationTokenExpiration,
      emailVerified: data.emailVerified,
      createdAt: now,
      updatedAt: now,
    });

    await t.save(Profile, {
      id: userId,
      userId: userId,
      username: data.name,
      birthday: data.birthday,
      imageUrl: data.profileImageUrl,
    });
  }

