  private async prepareTokenAndSendSignUpLinkEmail(
    userId: string,
    email: string,
    lang: string,
    logInfo: {
      teamId: string;
      requesterUid: string;
    },
  ) {
    const randomHexData = StringUtil.getRandomHex();

    const tokenExpirationDate = moment(new Date())
      .add(this.configProvider.config.defaultTokenExpirationSeconds, 'seconds')
      .toDate();

    await this.datasource.manager.transaction(async (t) => {
      await t.update(
        User,
        {
          id: userId,
        },
        {
          emailVerificationToken: randomHexData.hex,
          emailVerificationTokenExpiration: tokenExpirationDate,
        },
      );
    });

    await this.emailProvider.sendSignUpLinkEmail({
      userId: userId,
      email: email,
      token: randomHexData.hex,
      lang,
    });

    const exprStr = moment(tokenExpirationDate).format(
      AppConstants.default_datetime_format,
    );
    this.logger.log(
      `User: [${email}](id=${userId}) is invited to team_id=[${logInfo.teamId}]` +
        `, expiration: ${exprStr}, invited by: ${logInfo.requesterUid}`,
    );
  }

  @CodedMethod('CEVS')
  async checkEmailVerificationStatus(email: string) {
    const cbuilder = this.getCodeBuilder();
    return await this.datasource.manager.transaction(async (t) => {
      const user = await this.usersPersistence.findUserByEmail(t, email);
      if (!user) {
        return {
          status: 'not_created', // Change to 'unknown' if you want to hide existence of the account
        };
      } else if (user.emailVerified) {
        return {
          status: 'verified', // Change to 'unknown' if you want to hide existence of the account
        };
      }

      return {
        status: 'not_verified',
      };
    });
  }

  @CodedMethod('CPU')
  async createPersonalUser(
    email: string,
    name?: string,
    birthday?: string | null,
    requestContext: {
      lang: string | null;
    } = {
      lang: null,
    },
    mode: 'code' | 'link' = 'code',
  ): Promise<{
    userId: string;
  }> {
    const cbuilder = this.getCodeBuilder();
    if (birthday && !this.canRegisterUser(birthday)) {
      throw new CodedInvalidArgumentException(
        this.code,
        this.EC.USER_MUST_BE_AT_LEAST_13_YEARS_OLD(cbuilder.build()),
      );
    }
    const now = new Date();

    const targetUser = await this.cleanUserIfDeactivated(email, {
      joinProfileOnUser: true,
      throwErrorIfUserIsActive: true,
      throwErrorIfUserIsUnconfirmed: false,
    });

    const randomHexData = StringUtil.getRandomHex();
    const code = Math.floor(
      StringUtil.getRandomHex().number % 1000000,
    ).toString();

    const userId = await this.datasource.manager.transaction(async (t) => {
      // Check user existence
      const existingUser = await this.usersPersistence.findUserByEmail(
        t,
        email,
      );

      // Check team existence
      const existingTeam = existingUser
        ? await t.findOne(Team, {
            where: {
              teamType: TeamType.SINGLE,
              deletedAt: IsNull(),
              deletionScheduledAt: IsNull(),
              userRoles: {
                userId: existingUser.id,
              },
            },
          })
        : null;

      const userId = existingUser?.id ?? uuidv4();
      let teamId = existingTeam?.id;
      if (!existingTeam) {
        // Create a team first.

        const teamName = this.i18n.translate('_.initial.team_name', {
          lang: requestContext.lang ?? 'en',
        });
        const { team } = await this.teamsPersistence.createTeamWithItem(t, {
          name: teamName,
          ownerUserId: userId,
          teamType: TeamType.SINGLE,
          itemName: 'Free Sample',
        });
        teamId = team.id;
      }

      // Create a user.

      const tokenExpirationDate = moment(new Date())
        .add(
          this.configProvider.config.defaultTokenExpirationSeconds,
          'seconds',
        )
        .toDate();

      birthday =
        birthday ??
        (targetUser.user?.profile.birthday
          ? moment(targetUser.user?.profile.birthday).format('YYYY-MM-DD')
          : null);

      await this.createInitialUserData(
        t,
        userId,
        {
          email,
          name: name ?? targetUser.user?.profile.username ?? email,
          profileImageUrl: null,
          birthday,
          verificationCode: code,
          verificationCodeExpiration: moment(now).add(1, 'day').toDate(),
          ...(mode === 'link'
            ? {
                emailVerificationToken: randomHexData.hex,
                emailVerificationTokenExpiration: tokenExpirationDate,
              }
            : {}),
        },
        { lang: requestContext.lang },
      );

      if (!existingTeam) {
        // かつてこのメソッド内でuserId, teamIdが同一のUserRoleを削除していた。
        // このteamIdは新しく作られているため、削除の必要はない。
        // 他の呼び出し箇所も同様のため、削除を削除。
        await this.createInitialUserRole(t, userId, teamId!, 'personal_user');

        await this.createInitialPlayerForSingleTeam(
          t,
          userId,
          teamId!,
          birthday,
          requestContext,
        );
      }

      return userId;
    });

    if (mode === 'link') {
      await this.emailProvider.sendSignUpLinkEmail({
        userId,
        email,
        token: randomHexData.hex,
        lang: requestContext.lang,
      });
      return {
        userId,
      };
    } else {
      await this.emailProvider.sendSignUpCodeEmail({
        email,
        code,
        lang: requestContext.lang,
      });
      return {
        userId,
      };
    }
  }

  private async createInitialPlayerForSingleTeam(
