  @CodedMethod('GUTK')
  async getUserToken(
    email: string,
    password: string,
  ): Promise<{
    accessToken: string | null;
  }> {
    const cbuilder = this.getCodeBuilder();
    const user = await this.datasource.manager.transaction(async (t) => {
