  // For super_admin only so far.
  @CodedMethod('CUWT')
  async createUserWithTeam(
    data: TeamAndUserCreateDtoValidated,
    requesterUid: string,
    requestContext: { lang: string | null } = { lang: null },
  ): Promise<{
    user: User;
    team: Team;
  }> {
    const cbuilder = this.getCodeBuilder();

    const email = data.ownerEmail;
    const birthday = data.ownerBirthday;

    if (birthday && !this.canRegisterUser(birthday)) {
      throw new CodedInvalidArgumentException(
        this.code,
        this.EC.USER_MUST_BE_AT_LEAST_13_YEARS_OLD(cbuilder.build()),
      );
    }

    const plan = await this.datasource.manager.transaction(async (t) => {
      const userToCheck = await this.usersPersistence.findUserByEmail(t, email);
      if (userToCheck) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.USER_ALREADY_IN_USE(cbuilder.build()),
        );
      }

      const roleGroup = await t.findOne(RoleGroup, {
        where: {
          name: data.ownerRoleGroupName,
        },
      });
      if (!roleGroup) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.INVALID_ROLE_GROUP_ID(cbuilder.build()),
        );
      }

      const subscription = await t.findOne(Subscription, {
        where: {
          id: data.planId,
        },
      });
      if (!subscription) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.INVALID_PLAN_ID(cbuilder.build()),
        );
      }
      return subscription;
    });

    const cleanedUser = await this.cleanUserIfDeactivated(email, {
      throwErrorIfUserIsActive: true,
      throwErrorIfUserIsUnconfirmed: true,
    });

    const userId = uuidv4();

    // Create a team first.
    const { team } = await this.datasource.manager.transaction(async (t) => {
      return await this.teamsPersistence.createTeamWithSubscription(t, {
        name: data.name,
        ownerUserId: userId,
        teamType: TeamType.MULTIPLE, // DTO assumes this team is multiple.
        subscriptionId: plan.id,
        startDate: data.teamPlanStartDate,
        endDate: data.teamPlanEndDate,
      });
    });
    const teamId = team?.id;

    const user = await this.datasource.manager.transaction(async (t) => {
      // Create a user.
      await this.createInitialUserData(
        t,
        userId,
        {
          name: data.ownerUserName!, // teamAndUserCreateDtoValidator asserts not nullable and undefined.
          email: email,
          birthday: birthday ?? null,
          ...(data.ownerPassword
            ? {
                hashedPassword: await bcrypt.hash(
                  data.ownerPassword,
                  AppConstants.bcryptRounds,
                ),
                emailVerified: true,
              }
            : {}),
        },
        requestContext,
      );

      // かつてこのメソッド内でuserId, teamIdが同一のUserRoleを削除していた。
      // このteamIdは新しく作られているため、削除の必要はない。
      // 他の呼び出し箇所も同様のため、削除を削除。
      await this.createInitialUserRole(
        t,
        userId,
        teamId,
        data.ownerRoleGroupName,
      );

      return _.first(await this.usersPersistence.getUsers(t, [userId], {}))!;
    });

    if (data.ownerPassword) {
      // Creates a user with password.
      if (!cleanedUser.user || cleanedUser.isDeleted) {
        await this.cognitoProvider.createUser(userId, email);
      }
      await this.cognitoProvider.setUserPassword(userId, data.ownerPassword);
    } else {
      // Sets a verification token and send email (the same as invitation process).
      await this.prepareTokenAndSendSignUpLinkEmail(
        userId,
        email,
        data.language ?? 'en',
        {
          teamId,
          requesterUid,
        },
      );
    }

    return {
      user: user!,
      team: team!,
    };
  }

  @CodedMethod('IU')
  async inviteUser(
    teamId: string,
    email: string,
    roleGroupName: RoleGroupName,
    userName: string,
    redirectTo: string | null,
    requesterUid: string,
    requestContext: {
      lang: string | null;
    } = {
      lang: null,
    },
  ): Promise<{ user: MinimumUserInfo }> {
    const cbuilder = this.getCodeBuilder();

    // Check if the team is a single user team
    const team = await this.datasource.manager.findOne(Team, {
      where: {
        id: teamId,
      },
    });

    // Existence of team is assumed by the TeamAccessGuard of the caller controller.

    if (team!.teamType === TeamType.SINGLE) {
      throw new CodedInvalidArgumentException(
        this.code,
        this.EC.SINGLE_USER_TEAM_INVITATION_NOT_ALLOWED(cbuilder.build()),
      );
    } else {
      await this.datasource.manager.transaction(async (t) => {
        await this.limitsService.checkUserRolesCount(t, teamId);
      });
    }

    await this.cleanUserIfDeactivated(email, {
      throwErrorIfUserIsActive: false,
      throwErrorIfUserIsUnconfirmed: false,
    });

    const tranResult = await this.datasource.manager.transaction(async (t) => {
      return this.usersPersistence.findUserByEmail(t, email);
    });

    // Deletes all roles of the team and create new ones.
    if (tranResult) {
      const team = await this.datasource.manager.transaction(async (t) => {
        const roleGroup = await t.findOne(RoleGroup, {
          where: {
            name: roleGroupName,
          },
        });
        await t.delete(UserRole, {
          userId: tranResult.id,
          teamId,
        });
        await t.insert(UserRole, {
          userId: tranResult.id,
          teamId,
          roleGroupId: roleGroup!.id,
        });

        // User, Team, UserRoleの作成後に呼び出す必要がある。
        await this.usersPersistence.reactivateUsersIfNeeded(t, [tranResult.id]);

        return await t.findOne(Team, {
          where: {
            id: teamId,
          },
        });
      });

      // Send an email to the invited user for notification.
      //
      // Note: argument lang is a language setting for inviter, not invitee.
      // For now, the language setting is not stored on the server side but only exists on
      // the client side local storage, so invitee language setting is not considered here.
      // Similar implementation exists on the other API.
      await this.emailProvider.sendTeamInvitationEmailToExistingUser({
        userId: tranResult.id,
        email: email,
        team: team!.name, // it's ok to use ! as team must be non-null
        lang: requestContext.lang,
      });

      // Finishes invitation process if the user exists.
      return {
        user: {
          id: tranResult.id,
          email,
        },
      };
    }

    // The following process is executed when the email is not used.

    const userId = uuidv4();

    // Creates new user.
    await this.datasource.manager.transaction(async (t) => {
      await this.createInitialUserData(
        t,
        userId,
        {
          name: userName,
          email,
        },
        { lang: requestContext.lang },
      );

      // かつてこのメソッド内でuserId, teamIdが同一のUserRoleを削除していた。
      // このuserIdは新しく作られているため、削除の必要はない。
      // 他の呼び出し箇所も同様のため、削除を削除。
      await this.createInitialUserRole(t, userId, teamId, roleGroupName);

      // User, Team, UserRoleの作成後に呼び出す必要がある。
      await this.usersPersistence.reactivateUsersIfNeeded(t, [userId]);
    });

    await this.prepareTokenAndSendSignUpLinkEmail(
      userId,
      email,
      requestContext.lang ?? 'en',
      {
        teamId,
        requesterUid,
      },
    );

    return {
      user: {
        id: userId,
        email,
      },
    };
  }

  @CodedMethod('GRI')
  async getRoleInfo(userId: string): Promise<{
    checker: RoleChecker;
  }> {
    const cbuilder = this.getCodeBuilder();

    const tranResult = await this.datasource.manager.transaction(async (t) => {
      const userRoles = await t.find(UserRole, {
        where: {
          userId: userId,
          deleteFlag: false,
          user: {
            deletedAt: IsNull(),
            deletionScheduledAt: IsNull(),
          },
          team: {
            deletedAt: IsNull(),
            deletionScheduledAt: IsNull(),
          },
        },
        relations: {
          roleGroup: {
            roles: true,
          },
        },
      });

      if (_.isEmpty(userRoles)) {
        throw new CodedForbiddenException(
          this.code,
          this.EC.USER_UNAVAILABLE(cbuilder.build()),
        );
      }

      const isSuperUserLike = !!userRoles.find(
        (ur) => ur.roleGroup.isAllTeamsAccess,
      );
      const teamIdsForSuperUser = isSuperUserLike
        ? (
            await t.find(Team, {
              select: {
                id: true,
              },
              where: {
                deletedAt: IsNull(),
              },
            })
          ).map((t) => t.id)
        : [];

      return {
        checker: new RoleChecker(
          _.chain(userRoles)
            .groupBy((r) => r.teamId)
            .mapValues((inTeamUserRoles) =>
              UserRole.createDomainAndLevelMap(inTeamUserRoles),
            )
            .value(),
          _.chain(userRoles)
            .filter((r) => r.roleGroup.isAllTeamsAccess)
            .thru((userRoles) => UserRole.createDomainAndLevelMap(userRoles))
            .value(),
          teamIdsForSuperUser,
        ),
      };
    });

    return {
      checker: tranResult.checker,
    };
  }

