  @CodedMethod('EUPR')
  async editUserRole(
    teamId: string,
    targetUid: string,
    roleGroupName: RoleGroupName,
  ): Promise<{ user: User }> {
    const cbuilder = this.getCodeBuilder();

    const tranResult = await this.datasource.manager.transaction(async (t) => {
      /*
       * Validate the role change:
       * After the role change, a team must have at least 1 team_admin.
       */

      const currentRole = await t.findOne(UserRole, {
        where: {
          userId: targetUid,
          teamId: teamId,
          deleteFlag: false,
        },
        relations: {
          roleGroup: true,
        },
      });

      if (currentRole?.roleGroup.name == 'personal_user') {
        // coming here means the only one personal_user in a single team is being changed to other role,
        // but this must not happen because a single team must have at least 1 personal_user.
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.PERSONAL_USER_ABSENCE(cbuilder.build()),
        );
      }

      const currentTeamAdminsCount = await t.count(UserRole, {
        where: {
          teamId: teamId,
          deleteFlag: false,
          roleGroup: {
            name: 'team_admin',
          },
        },
      });

      if (
        currentTeamAdminsCount == 1 &&
        currentRole?.roleGroup.name == 'team_admin' &&
        roleGroupName != 'team_admin'
      ) {
        // coming here means the only one team_admin in a multiple team is being changed to other role,
        // but this must not happen because a multiple team must have at least 1 team_admin.
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.TEAM_ADMIN_ABSENCE(cbuilder.build()),
        );
      }

      await t.delete(UserRole, {
        userId: targetUid,
        teamId: teamId,
      });
      const roleGroup = await t.findOne(RoleGroup, {
        where: {
          name: roleGroupName,
        },
      });
      const groupId = roleGroup!.id;
      await t.insert(UserRole, [
        {
          userId: targetUid,
          teamId: teamId,
          roleGroupId: groupId,
        },
      ]);

      this.logger.log(
        `Role updated: user_id=${targetUid}, team_id=${teamId}, role_group_id=${groupId}`,
      );

      return _.first(await this.usersPersistence.getUsers(t, [targetUid]));
    });

    return {
      user: tranResult!,
    };
  }

  @CodedMethod('PCUE')
  async prepareToChangeUserEmail(
    targetUserId: string,
    newEmail: string,
    redirectTo: string | null,
    requestContext: {
      lang: string | null;
    },
  ) {
    const cbuilder = this.getCodeBuilder();
    const tranResult = await this.datasource.manager.transaction(async (t) => {
      const user = await t.findOne(User, {
        where: {
          id: targetUserId,
        },
      });

      if (!user?.email) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.USER_NOT_FOUND(cbuilder.build()),
        );
      }

      const emailOwner = await t.findOne(User, {
        where: {
          email: newEmail,
        },
      });

      if (emailOwner) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.USER_ALREADY_IN_USE(cbuilder.build()),
        );
      }

      const randomHexData = StringUtil.getRandomHex();

      await t.update(
        User,
        {
          id: targetUserId,
        },
        {
          emailVerificationToken: randomHexData.hex,
          emailVerificationTokenExpiration: moment(new Date())
            .add(
              this.configProvider.config.defaultTokenExpirationSeconds,
              'seconds',
            )
            .toDate(),
        },
      );

      return {
        email: user.email,
        token: randomHexData.hex,
      };
    });

    await this.emailProvider.sendEmailChangingEmail(targetUserId, {
      oldEmail: tranResult.email,
      newEmail,
      token: tranResult.token,
      redirectTo: redirectTo, // top
      lang: requestContext.lang,
    });

    this.logger.log(
      `email changing email is sent, id: ${targetUserId}, email: [${tranResult.email}].`,
    );
  }

  @CodedMethod('VAC')
  async verifyAuthCode(email: string, code: string) {
    const cbuilder = this.getCodeBuilder();

    const now = new Date();
    const token = StringUtil.getRandomHex().hex;

    return await this.datasource.manager.transaction(async (t) => {
      const user = await this.usersPersistence.findUserByEmail(t, email);

      if (!user) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.INVALID_URL(cbuilder.build()),
        );
      }

      if (user.verificationCode != code) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.INVALID_CODE(cbuilder.build()),
        );
      }

      if (
        !user.verificationCodeExpiration ||
        moment(user.verificationCodeExpiration) < moment(new Date())
      ) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.LINK_EXPIRED(cbuilder.build()),
        );
      }

      await t.update(
        User,
        {
          id: user.id,
        },
        {
          verificationCode: null,
          verificationCodeExpiration: null,
          emailVerified: true,
          temporallyToken: token,
          temporallyTokenExpiration: moment(now).add(5, 'minutes').toDate(),
        },
      );

      return token;
    });
  }

  @CodedMethod('CEWT')
  async changeEmailWithToken(
    targetUserId: string,
    newEmail: string,
    token: string,
    hashedEmail: string,
  ): Promise<{
    message: string;
    isOk: boolean;
  }> {
    const cbuilder = this.getCodeBuilder();

    // Verify hashedEmail to confirm the passed `newEmail` is not falsified.
    if (
      hashedEmail !=
      StringUtil.getAppHash(
        newEmail,
        this.configProvider.config.appSecretKey,
        'hex',
      )
    ) {
      return {
        message: 'Invalid token.',
        isOk: false,
      };
    }

    return await this.datasource.manager.transaction(async (t) => {
      const user = await t.findOne(User, {
        where: {
          id: targetUserId,
          emailVerificationToken: token,
          deletedAt: IsNull(),
          deletionScheduledAt: IsNull(),
        },
      });

      if (!user) {
        return {
          message: 'Invalid token or the email is already verified.',
          isOk: false,
        };
      }

      const oldEmail = user.email;

      if (
        !user.emailVerificationTokenExpiration ||
        moment(user.emailVerificationTokenExpiration) < moment(new Date())
      ) {
        return {
          message: 'The link is expired.',
          isOk: false,
        };
      }

      await t.update(
        User,
        {
          id: targetUserId,
        },
        {
          email: newEmail,
          emailVerificationToken: null,
          emailVerificationTokenExpiration: null,
        },
      );

      await this.cognitoProvider.updateUserEmail(targetUserId, newEmail);

      this.logger.log(
        `Email updated, id: ${targetUserId}, old email: [${oldEmail}], new email: [${newEmail}].`,
      );

      return {
        message: `The email: ${newEmail} is successfully verified.`,
        isOk: true,
      };
    });
  }

  @CodedMethod('SPRE')
  async sendPasswordResetEmail(
    email: string,
