  @CodedMethod('CPWT')
  async changePasswordWithToken(
    targetUserId: string,
    password: string,
    token: string,
    mode: 'initial' | 'reset',
  ): Promise<void> {
    const cbuilder = this.getCodeBuilder();
    const now = new Date();

    const user = await this.datasource.manager.transaction(async (t) => {
      const user = await t.findOne(User, {
        where: {
          id: targetUserId,
          deletedAt: IsNull(),
          deletionScheduledAt: IsNull(),
        },
      });

      if (!user) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.INVALID_URL(cbuilder.build()),
        );
      }

      if (mode == 'reset') {
        if (user.emailVerificationToken != token) {
          throw new CodedInvalidArgumentException(
            this.code,
            this.EC.INVALID_TOKEN(cbuilder.build()),
          );
        }

        if (
          !user.emailVerificationTokenExpiration ||
          moment(user.emailVerificationTokenExpiration) < moment(new Date())
        ) {
          throw new CodedInvalidArgumentException(
            this.code,
            this.EC.LINK_EXPIRED(cbuilder.build()),
          );
        }

        await t.update(
          User,
          {
            id: targetUserId,
          },
          {
            hashedPassword: await bcrypt.hash(
              password,
              AppConstants.bcryptRounds,
            ),
            passwordUpdatedDate: now,
            emailVerificationToken: null,
            emailVerificationTokenExpiration: null,
            emailVerified: true,
          },
        );
      } else {
        // initial mode (signup flow)
        if (user.temporallyToken != token) {
          throw new CodedInvalidArgumentException(
            this.code,
            this.EC.INVALID_TOKEN(cbuilder.build()),
          );
        }

        if (
          !user.temporallyTokenExpiration ||
          moment(user.temporallyTokenExpiration) < moment(new Date())
        ) {
          throw new CodedInvalidArgumentException(
            this.code,
            this.EC.LINK_EXPIRED(cbuilder.build()),
          );
        }

        await t.update(
          User,
          {
            id: targetUserId,
          },
          {
            hashedPassword: await bcrypt.hash(
              password,
              AppConstants.bcryptRounds,
            ),
            passwordUpdatedDate: now,
            temporallyToken: null,
            temporallyTokenExpiration: null,
            emailVerified: true,
          },
        );
      }

      if (!(await this.cognitoProvider.getUser(user.id))) {
        await this.cognitoProvider.createUser(user.id, user.email!);
      }
      await this.cognitoProvider.setUserPassword(targetUserId, password);

      return user;
    });

    this.logger.log(
      `The password of the user: ${targetUserId} is changed (w/ token).`,
    );
  }

