  @CodedMethod('DAU')
  async deactivateUser(
    teamId: string,
    targetUserId: string,
  ): Promise<{ user: MinimumUserInfo }> {
    const cbuilder = this.getCodeBuilder();
    const user = await this.datasource.manager.transaction(async (t) => {
      const dbUser = await t.findOne(User, {
        where: {
          id: targetUserId,
          deletedAt: IsNull(),
          userRoles: {
            teamId,
          },
        },
      });

      if (!dbUser) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.INVALID_USER_ID(cbuilder.build()),
        );
      }

      /*
       * Validate the role change:
       * After the role change, a team must have at least 1 team_admin.
       */

      const currentRole = await t.findOne(UserRole, {
        where: {
          userId: targetUserId,
          teamId: teamId,
          deleteFlag: false,
        },
        relations: {
          roleGroup: true,
        },
      });

      if (currentRole?.roleGroup.name == 'personal_user') {
        // coming here means the only one personal_user in a single team is being changed to other role,
        // but this must not happen because a single team must have at least 1 personal_user.
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.PERSONAL_USER_ABSENCE(cbuilder.build()),
        );
      }

      const currentTeamAdminsCount = await t.count(UserRole, {
        where: {
          teamId: teamId,
          deleteFlag: false,
          roleGroup: {
            name: 'team_admin',
          },
        },
      });

      if (
        currentTeamAdminsCount == 1 &&
        currentRole?.roleGroup.name == 'team_admin'
      ) {
        // coming here means the only one team_admin in a team is being deactivated,
        // but this must not happen because a team must have at least 1 team_admin.
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.TEAM_ADMIN_ABSENCE(cbuilder.build()),
        );
      }

      await t.update(
        UserRole,
        {
          userId: targetUserId,
          teamId: teamId,
        },
        {
          deleteFlag: true,
        },
      );

      await this.usersPersistence.deactivateUsersIfNeeded(t, [targetUserId], {
        deletionReason: 'team_leave',
      });

      return dbUser;
    });

    this.logger.log(`User: ${targetUserId} is deactivated. team_id=${teamId}`);

    return {
      user: {
        id: user.id,
        email: user.email,
      },
    };
  }

