  @CodedMethod('UUI')
  async uploadUserImage(
    userId: string,
    localFilePath: string,
    data: {
      ext: string;
    },
  ): Promise<{ url: string }> {
    const cbuilder = this.getCodeBuilder();

    const tranResult = await this.datasource.manager.transaction(async (t) => {
      // consistency check
      const userToCheck = await t.findOne(User, {
        where: {
          id: userId,
        },
        relations: {
          profile: true,
        },
      });

      if (!userToCheck) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.INVALID_USER_ID(cbuilder.build()),
        );
      }

      return userToCheck;
    });

    await ImageCompressionUtil.compressImage(localFilePath);

    const filePrefix = `images/users/${userId}/thumbnail-`;
    const { url } = await this.storageProvider.uploadToBucket(
      `${filePrefix}${uuidv4()}.${data.ext}`,
      localFilePath,
    );

    const currentImages = (
      await this.storageProvider.listImages(filePrefix)
    ).map((x) =>
      this.storageProvider.getFixedFilePathFromImageUrl(x as string, 'image'),
    );
    const filesToKeep = [tranResult.profile.imageUrl, url]
      .filter((x) => !!x)
      .map((x) =>
        this.storageProvider.getFixedFilePathFromImageUrl(x as string, 'image'),
      );
    await this.storageProvider.deleteImages(
      _.difference(currentImages, filesToKeep),
    );

    return {
      url,
    };
  }

  async checkPassword(data: PasswordCheckDtoValidated) {
    // If email verification is not completed, the user will not be migrated.
    const user = await this.datasource.transaction(async (t) => {
      return this.usersPersistence.findUserByEmail(t, data.email, {
        limitToEmailVerifiedUser: true,
      });
    });

    if (!user) {
      return {
        id: null,
        result: false,
        reason: 'user-not-found',
      };
    }

    const result = await bcrypt.compare(
      data.password,
      user.hashedPassword ?? '',
    );

    return {
      id: user.id,
      result: result,
      reason: result ? '' : 'incorrect-password',
    };
  }

  async verifyStatus(data: UserStatusVerifyDtoValidated) {
    const user = await this.datasource.manager.findOne(User, {
      where: {
        id: data.userId,
      },
    });

    if (!user) {
      return {
        result: false,
        reason: 'user-not-found',
      };
    }

    return {
      result: !user.deletionScheduledAt && !user.deletedAt,
      reason: user.deletionScheduledAt || user.deletedAt ? 'hibernated' : '',
    };
  }

  @CodedMethod('GNU')
  async getNotificationsForUser(
    userId: string,
    data: NotificationForUserSearchDtoValidated,
    requestContext: {
      lang: string | null;
    },
  ): Promise<{ notifications: StructuredNotification[]; total: number }> {
    const cbuilder = this.getCodeBuilder();

    const tranResult = await this.datasource.manager.transaction(async (t) => {
      const dbUser = await t.findOne(User, {
        where: {
          id: userId,
        },
        relations: {
          userRoles: {
            team: true,
          },
        },
      });

      if (!dbUser) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.INVALID_USER_ID(cbuilder.build()),
        );
      }

      // Get user's team types (multiple or single)
      const userTeamTypes = _.uniq(
        dbUser.userRoles.map((role) => role.team.teamType),
      );

      // Build targetTeamTypes filter based on user's teams
      const targetTeamTypesFilter: ('multiple' | 'single')[] =
        userTeamTypes.length > 0 ? userTeamTypes : ['multiple', 'single'];

      const { notificationIds, total } =
        await this.notificationsPersistence.searchNotifications(t, {
          ...data,
          includeOnlyPublishedNotifications: true,
          targetTeamTypes: targetTeamTypesFilter,
          publishAtFrom: moment(dbUser.createdAt).subtract(1, 'month').toDate(),
        });

      const notifications =
        await this.notificationsPersistence.getNotifications(
          t,
          notificationIds,
          {
            userId,
          },
        );

      return {
        notifications,
        total,
      };
    });

    return {
      notifications: tranResult.notifications,
      total: tranResult.total,
    };
  }

  @CodedMethod('SNR')
  async setNotificationAsRead(
    userId: string,
    notificationId: string,
    isRead: boolean,
  ): Promise<{ userNotification: UserNotification }> {
    const cbuilder = this.getCodeBuilder();

    const tranResult = await this.datasource.manager.transaction(async (t) => {
      const dbUser = await t.findOne(User, {
        where: {
          id: userId,
        },
      });

      if (!dbUser) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.INVALID_USER_ID(cbuilder.build()),
        );
      }

      const userNotificationToCheck = await t.findOne(Notification, {
        where: {
          id: notificationId,
        },
      });

      if (!userNotificationToCheck) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.INVALID_NOTIFICATION_ID(cbuilder.build()),
        );
      }

      await this.notificationsPersistence.upsertUserNotifications(
        t,
        userId,
        [notificationId],
        isRead,
      );

      return {
        userNotification: await t.findOne(UserNotification, {
          where: {
            userId,
            notificationId,
          },
        }),
      };
    });

    return {
      userNotification: tranResult.userNotification!,
    };
  }

  @CodedMethod('SANR')
  async setAllNotificationsAsRead(
    userId: string,
    data: UserNotificationUpdateDtoValidated,
  ): Promise<{ status: boolean }> {
    const cbuilder = this.getCodeBuilder();

    const tranResult = await this.datasource.manager.transaction(async (t) => {
      const dbUser = await t.findOne(User, {
        where: {
          id: userId,
        },
      });

      if (!dbUser) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.INVALID_USER_ID(cbuilder.build()),
        );
      }

      const { notificationIds } =
        await this.notificationsPersistence.searchNotifications(t, {
          targetType: data.targetType,
          pageSize: 100000,
          publishAtFrom: moment(dbUser.createdAt).subtract(1, 'month').toDate(),
        });

      await this.notificationsPersistence.upsertUserNotifications(
        t,
        userId,
        notificationIds,
        data.isRead,
      );

      return {
        isRead: data.isRead,
      };
    });

    return {
      status: tranResult.isRead,
    };
  }

  async deleteScheduledUsers(now?: Date) {
    now ??= new Date();

    // NOTE: Users who are linked to a team and scheduled for deletion
    // will only be deleted if the team is also deleted.
    const userIdsLinkedToDeletedTeams =
      await this.datasource.manager.transaction(async (t) => {
        const deletedTeamIds = (
          await t.find(TeamDeletionRecord, {
            where: {
              status: 'completed',
            },
          })
        ).map((r) => r.teamId);

        if (_.isEmpty(deletedTeamIds)) {
          return [];
        }

        return (
          await t.find(UserDeletionRecord, {
            where: {
              status: 'scheduled',
              scheduledDeletionDate: LessThanOrEqual(now),
              deletionReason: 'team_deletion',
              linkedTeamId: In(deletedTeamIds),
            },
          })
        ).map((r) => r.userId);
      });

    if (!_.isEmpty(userIdsLinkedToDeletedTeams)) {
      await this.deleteUsers(userIdsLinkedToDeletedTeams, now);
    }

    const userIds = await this.datasource.manager.transaction(async (t) => {
      return (
        await t.find(UserDeletionRecord, {
          where: {
            status: 'scheduled',
            scheduledDeletionDate: LessThanOrEqual(now),
            deletionReason: Not<UserDeletionReason>('team_deletion'),
          },
        })
      ).map((r) => r.userId);
    });

    await this.deleteUsers(userIds, now);
  }

  // WARNING: This function will delete users without any confirmation. Use with care.
  private async deleteUsers(userIdsToDeleted: string[], now?: Date) {
    now ??= new Date();

    // Delete cognito user accounts
    // NOTE: To prevent transaction stalls due to long-running operations,
    // this is executed outside the DB transaction.
    const deletedUserIds = [] as string[];
    for (const [i, chunk] of Object.entries(_.chunk(userIdsToDeleted, 20))) {
      if (+i) {
        // To avoid Cognito quotas
        await TimeUtil.sleep(1000);
      }

      for (const userId of chunk) {
        try {
          await this.cognitoProvider.deleteAccount(userId);
        } catch (e) {
          this.logger.error(`failed to delete cognito account: ${userId}`);
          continue;
        }
        deletedUserIds.push(userId);
      }
    }

    // Delete S3 images that belong to users
    const imagesToDelete: string[] = [];
    for (const userId of userIdsToDeleted) {
      const filePrefix = `images/users/${userId}/`;
      imagesToDelete.push(
        ...(await this.storageProvider.listImages(filePrefix)),
      );
    }
    if (!_.isEmpty(imagesToDelete)) {
      await this.storageProvider.deleteImages(imagesToDelete);
    }

    await this.datasource.manager.transaction(async (t) => {
      // Nullify user id
      await t.update(
        BallPosition,
        { userId: In(deletedUserIds) },
        { userId: null },
      );
      await t.update(Ball, { userId: In(deletedUserIds) }, { userId: null });
      await t.update(
        BoundingBox,
        { userId: In(deletedUserIds) },
        { userId: null },
      );
      await t.update(Player, { userId: In(deletedUserIds) }, { userId: null });
      await t.update(
        Resource,
        { userId: In(deletedUserIds) },
        { userId: null },
      );
      await t.update(Session, { userId: In(deletedUserIds) }, { userId: null });

      // Delete user related data
      await t.delete(Profile, { id: In(deletedUserIds) });
      await t.delete(UserRole, { userId: In(deletedUserIds) });
      await t.delete(UserNotification, { userId: In(deletedUserIds) });
      await t.delete(User, { id: In(deletedUserIds) });

      // Record successful deletions
      // (No error occurs if the record does not exist)
      await t.update(
        UserDeletionRecord,
        {
          userId: In(deletedUserIds),
          status: 'scheduled',
        },
        {
          status: 'completed',
          completedAt: now,
        },
      );
    });
  }

  @CodedMethod('UB')
  async updateUserBirthday(
    userId: string,
    birthday: string,
  ): Promise<{ user: User }> {
    const cbuilder = this.getCodeBuilder();
    if (!this.canRegisterUser(birthday)) {
      throw new CodedInvalidArgumentException(
        this.code,
        this.EC.USER_MUST_BE_AT_LEAST_13_YEARS_OLD(cbuilder.build()),
      );
    }
    const tranResult = await this.datasource.manager.transaction(async (t) => {
      const profile = await t.findOne(Profile, {
        where: {
          id: userId,
        },
      });

      if (!profile) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.INVALID_USER_ID(cbuilder.build()),
        );
      }

      if (profile.birthday !== null) {
        throw new CodedInvalidArgumentException(
          this.code,
          this.EC.BIRTHDAY_ALREADY_SET(cbuilder.build()),
        );
      }

      await t.update(Profile, { id: userId }, { birthday });

      return _.first(await this.usersPersistence.getUsers(t, [userId]));
    });

    return {
      user: tranResult!,
    };
  }

  canRegisterUser(birthday: string) {
    const birthDate = moment(birthday);
    const today = moment();
    const age = today.diff(birthDate, 'years');
    return age >= 13;
  }
}

