/// {@category DTO}
library;

// Package imports:
import 'package:freezed_annotation/freezed_annotation.dart';

part 'email_verification_status_response.freezed.dart';
part 'email_verification_status_response.g.dart';

@JsonEnum(fieldRename: FieldRename.snake)
enum EmailVerificationStatus {
  unknown,
  notCreated,
  notVerified,
  verified,
}

@freezed
abstract class EmailVerificationStatusResponse
    with _$EmailVerificationStatusResponse {
  @JsonSerializable(explicitToJson: true, fieldRename: FieldRename.none)
  const factory EmailVerificationStatusResponse({
    @JsonKey(unknownEnumValue: EmailVerificationStatus.unknown)
    required EmailVerificationStatus status,
  }) = _EmailVerificationStatusResponse;

  factory EmailVerificationStatusResponse.fromJson(Map<String, dynamic> json) =>
      _$EmailVerificationStatusResponseFromJson(json);
}

